('tpl-negroni', 'Negroni', 'The classic Italian aperitivo — equal parts gin, Campari, and sweet vermouth.', 'cocktail', '{"glass_type":"rocks","ice_type":"large_cube","method":"stirred","garnish":"Orange peel","difficulty":"easy","ingredients":[{"name":"Gin","amount":1,"unit":"oz"},{"name":"Campari","amount":1,"unit":"oz"},{"name":"Sweet vermouth","amount":1,"unit":"oz"}],"steps":[{"description":"Combine all ingredients in a mixing glass with ice."},{"description":"Stir for 30 seconds until well-chilled."},{"description":"Strain into a rocks glass over a large ice cube."},{"description":"Express an orange peel over the glass and use as garnish."}]}'),
('tpl-old-fashioned', 'Old Fashioned', 'The original cocktail — whiskey, sugar, bitters, and a twist.', 'cocktail', '{"glass_type":"rocks","ice_type":"large_cube","method":"stirred","garnish":"Orange peel and cherry","difficulty":"easy","ingredients":[{"name":"Bourbon or rye whiskey","amount":2,"unit":"oz"},{"name":"Simple syrup","amount":0.25,"unit":"oz"},{"name":"Angostura bitters","amount":2,"unit":"dash"},{"name":"Orange bitters","amount":1,"unit":"dash"}],"steps":[{"description":"Add sugar syrup and bitters to a rocks glass."},{"description":"Add ice and whiskey."},{"description":"Stir gently to combine."},{"description":"Express an orange peel over the glass and garnish with the peel and a cherry."}]}'),
('tpl-martini', 'Martini', 'The iconic gin-and-vermouth cocktail, served cold and crisp.', 'cocktail', '{"glass_type":"martini","ice_type":"none","method":"stirred","garnish":"Lemon twist or olive","difficulty":"easy","ingredients":[{"name":"Gin","amount":2.5,"unit":"oz"},{"name":"Dry vermouth","amount":0.5,"unit":"oz"}],"steps":[{"description":"Combine gin and vermouth in a mixing glass with plenty of ice."},{"description":"Stir for 30–40 seconds until very cold and diluted."},{"description":"Strain into a chilled martini glass."},{"description":"Garnish with a lemon twist or olive."}]}'),
('tpl-daiquiri', 'Daiquiri', 'A perfectly balanced sour — rum, lime, and sugar.', 'cocktail', '{"glass_type":"coupe","ice_type":"none","method":"shaken","garnish":"Lime wheel","difficulty":"easy","ingredients":[{"name":"White rum","amount":2,"unit":"oz"},{"name":"Fresh lime juice","amount":0.75,"unit":"oz"},{"name":"Simple syrup","amount":0.75,"unit":"oz"}],"steps":[{"description":"Combine all ingredients in a cocktail shaker with ice."},{"description":"Shake hard for 12–15 seconds."},{"description":"Double strain into a chilled coupe."},{"description":"Garnish with a lime wheel."}]}'),
('tpl-whiskey-sour', 'Whiskey Sour', 'A classic sour with bourbon, lemon, and optional egg white for froth.', 'cocktail', '{"glass_type":"rocks","ice_type":"cubed","method":"shaken","garnish":"Lemon slice and cherry","difficulty":"easy","ingredients":[{"name":"Bourbon","amount":2,"unit":"oz"},{"name":"Fresh lemon juice","amount":0.75,"unit":"oz"},{"name":"Simple syrup","amount":0.75,"unit":"oz"},{"name":"Egg white","amount":1,"unit":null}],"steps":[{"description":"Dry shake all ingredients without ice for 15 seconds to emulsify the egg white."},{"description":"Add ice and shake again for 12 seconds."},{"description":"Strain into a rocks glass over fresh ice."},{"description":"Garnish with a lemon slice and cherry."}]}'),
('tpl-manhattan', 'Manhattan', 'The quintessential whiskey cocktail — bold, spirit-forward, with a touch of vermouth and bitters.', 'cocktail', '{"glass_type":"nick_and_nora","ice_type":"none","method":"stirred","garnish":"Luxardo cherry","difficulty":"easy","ingredients":[{"name":"Rye whiskey","amount":2,"unit":"oz"},{"name":"Sweet vermouth","amount":1,"unit":"oz"},{"name":"Angostura bitters","amount":2,"unit":"dash"}],"steps":[{"description":"Combine all ingredients in a mixing glass with ice."},{"description":"Stir for 30 seconds until well-chilled."},{"description":"Strain into a chilled coupe or Nick & Nora glass."},{"description":"Garnish with a Luxardo cherry."}]}'),
