('tpl-tom-collins', 'Tom Collins', 'Gin, lemon, sugar, and soda — effervescent and easy.', 'cocktail', '{"glass_type":"highball","ice_type":"cubed","method":"built","garnish":"Lemon slice and cherry","difficulty":"easy","ingredients":[{"name":"Gin","amount":2,"unit":"oz"},{"name":"Fresh lemon juice","amount":1,"unit":"oz"},{"name":"Simple syrup","amount":0.75,"unit":"oz"},{"name":"Soda water","amount":3,"unit":"oz"}],"steps":[{"description":"Build gin, lemon juice, and syrup in a highball glass with ice."},{"description":"Top with soda water and stir briefly."},{"description":"Garnish with a lemon slice and cherry."}]}'),
