('tpl-sazerac', 'Sazerac', 'Rye whiskey, absinthe, Peychaud''s bitters, and sugar — New Orleans in a glass.', 'cocktail', '{"glass_type":"rocks","ice_type":"none","method":"stirred","garnish":"Lemon peel (expressed and discarded)","difficulty":"medium","ingredients":[{"name":"Rye whiskey","amount":2,"unit":"oz"},{"name":"Peychaud''s bitters","amount":3,"unit":"dash"},{"name":"Simple syrup","amount":0.25,"unit":"oz"},{"name":"Absinthe","amount":0.5,"unit":"barspoon"}],"steps":[{"description":"Rinse a chilled rocks glass with absinthe and discard the excess."},{"description":"Stir rye, bitters, and syrup with ice in a mixing glass."},{"description":"Strain into the prepared glass (neat, no ice)."},{"description":"Express a lemon peel over the glass and discard."}]}'),
