('tpl-demerara-syrup', 'Demerara Syrup', 'Rich, molasses-flavored syrup from unrefined cane sugar.', 'syrup', '{"glass_type":null,"ice_type":null,"method":"batch","garnish":null,"difficulty":"easy","ingredients":[{"name":"Demerara sugar","amount":2,"unit":"cup"},{"name":"Water","amount":1,"unit":"cup"}],"steps":[{"description":"Combine in a saucepan over low heat."},{"description":"Stir until dissolved, do not boil."},{"description":"Cool and bottle. Refrigerated for 3–4 weeks."}]}'),
('tpl-ginger-syrup', 'Ginger Syrup', 'Spicy, fresh ginger-infused syrup — essential for Moscow Mules and Dark & Stormys without the beer.', 'syrup', '{"glass_type":null,"ice_type":null,"method":"batch","garnish":null,"difficulty":"easy","ingredients":[{"name":"Fresh ginger (peeled and chopped)","amount":200,"unit":"g"},{"name":"White sugar","amount":1,"unit":"cup"},{"name":"Water","amount":1,"unit":"cup"}],"steps":[{"description":"Combine sugar and water over medium heat until dissolved."},{"description":"Add ginger and simmer 10 minutes."},{"description":"Cool, fine strain into a bottle. Keeps 2 weeks refrigerated."}]}'),
('tpl-orgeat', 'Orgeat', 'Almond syrup with orange blossom water — the soul of the Mai Tai.', 'syrup', '{"glass_type":null,"ice_type":null,"method":"batch","garnish":null,"difficulty":"medium","ingredients":[{"name":"Blanched almonds","amount":200,"unit":"g"},{"name":"White sugar","amount":1.5,"unit":"cup"},{"name":"Water","amount":1,"unit":"cup"},{"name":"Orange blossom water","amount":1,"unit":"tsp"},{"name":"Vodka (as preservative)","amount":1,"unit":"oz"}],"steps":[{"description":"Blend almonds with water until smooth."},{"description":"Strain through cheesecloth, squeezing to extract almond milk."},{"description":"Combine almond milk and sugar in a pan over medium heat until dissolved."},{"description":"Add orange blossom water and vodka."},{"description":"Bottle and refrigerate. Keeps 2–3 weeks."}]}'),
('tpl-angostura-bitters', 'Angostura-Style Aromatic Bitters', 'House aromatic bitters with clove, gentian, and cassia.', 'bitter', '{"glass_type":null,"ice_type":null,"method":"batch","garnish":null,"difficulty":"hard","ingredients":[{"name":"High-proof spirit (Everclear or similar)","amount":8,"unit":"oz"},{"name":"Gentian root","amount":2,"unit":"tsp"},{"name":"Cassia bark","amount":1,"unit":"tsp"},{"name":"Cloves","amount":5,"unit":null},{"name":"Dried orange peel","amount":1,"unit":"tbsp"},{"name":"Cardamom pods (cracked)","amount":3,"unit":null},{"name":"Dried cherries","amount":1,"unit":"tbsp"}],"steps":[{"description":"Combine all ingredients in a jar."},{"description":"Seal and shake. Infuse for 2 weeks, shaking daily."},{"description":"Strain through cheesecloth twice."},{"description":"Bottle and label. Shelf-stable."}]}'),
('tpl-strawberry-shrub', 'Strawberry Balsamic Shrub', 'Sweet-tart drinking vinegar with strawberry and aged balsamic.', 'shrub', '{"glass_type":null,"ice_type":null,"method":"batch","garnish":null,"difficulty":"medium","ingredients":[{"name":"Fresh strawberries (hulled and sliced)","amount":500,"unit":"g"},{"name":"White sugar","amount":1,"unit":"cup"},{"name":"Apple cider vinegar","amount":0.75,"unit":"cup"},{"name":"Aged balsamic vinegar","amount":0.25,"unit":"cup"}],"steps":[{"description":"Toss strawberries with sugar and let macerate 24 hours."},{"description":"Press out the juice through a fine strainer."},{"description":"Combine juice with vinegars."},{"description":"Bottle and refrigerate. Lasts 3 months."}]}');
